sub save_session {
    my ($session_id, $data) = @_;
    return unless $session_id && $data;
    
    # Validate session ID format
    return unless $session_id =~ /^[a-zA-Z0-9]+$/;
    
    my $session_file = "/tmp/sess_$session_id";
    
